type UiKey = keyof typeof uiText.es;
function t(language: Language, key: UiKey): string { return uiText[language][key]; }

const initialPipeline: api.PipelineStatus = { status: "idle", stage: "data_validation", progress: 0, message: "Listo para iniciar", detail: "Cargue el conjunto de datos desde EDA" };
const stages = [
  ["data_validation", "Carga"], ["data_cleaning", "Limpieza"], ["eda", "EDA"], ["preprocessing", "Preproceso"], ["cross_validation", "Validación cruzada"],
  ["tuning", "Ajuste"], ["model_training", "Modelos"], ["evaluation", "Evaluación"], ["reports", "Reportes"], ["ready", "Listo"],
];

function asRows(value: unknown): Row[] { return Array.isArray(value) ? value.filter((item): item is Row => typeof item === "object" && item !== null) : []; }
function asRow(value: unknown): Row { return typeof value === "object" && value !== null ? value as Row : {}; }
function num(value: unknown, digits = 3): string { return typeof value === "number" && Number.isFinite(value) ? value.toFixed(digits) : value == null ? "—" : String(value); }
function pct(value: unknown, digits = 1): string { return typeof value === "number" && Number.isFinite(value) ? `${(value * 100).toFixed(digits)}%` : "—"; }
function duration(seconds?: number | null): string { if (seconds == null || !Number.isFinite(seconds)) return "—"; return seconds < 60 ? `${Math.round(seconds)} s` : `${Math.floor(seconds / 60)} min ${Math.round(seconds % 60)} s`; }
const translatedLabels: Record<string, string> = {
  model: "Modelo", model_a: "Modelo A", model_b: "Modelo B", fold: "Pliegue", accuracy: "Exactitud", precision: "Precisión", recall: "Sensibilidad",
  specificity: "Especificidad", f1: "F1", roc_auc: "ROC-AUC", balanced_accuracy: "Exactitud balanceada", training_seconds: "Entrenamiento (s)",
  inference_seconds_per_row: "Inferencia por fila (s)", inference_p50_seconds: "Inferencia P50 (s)", inference_p95_seconds: "Inferencia P95 (s)",
  p_value: "Valor p", p_value_holm: "Valor p (Holm)", mean_difference: "Diferencia media", ci95_low: "IC95% inferior", ci95_high: "IC95% superior",
  t_statistic: "Estadístico t", cohen_d_paired: "d de Cohen", n: "n", n_nonzero: "n no nulo", positive_rank_sum: "Rangos positivos",
  negative_rank_sum: "Rangos negativos", statistic: "Estadístico", effect: "Efecto", temperature: "Temperatura", humidity: "Humedad",
  moi: "MOI", soil_type: "Tipo de suelo", crop_stage: "Etapa del cultivo", crop_id: "Identificador del cultivo", probability_irrigation: "Probabilidad de riego", predicted_class: "Clase predicha", recommendation: "Recomendación",
  confusion_matrix_best: "Matriz de confusión del mejor modelo", roc_curves_models: "Curvas ROC de los modelos", model_metrics_heatmap: "Mapa de calor de métricas por modelo",
  correlation_heatmap: "Mapa de calor de correlaciones", distribution_soil_type: "Distribución por tipo de suelo", distribution_crop_stage: "Distribución por etapa del cultivo",
  numeric_boxplots: "Diagramas de caja de variables numéricas", numeric_histograms: "Histogramas de variables numéricas",
  skipped_fast: "omitido en modo rápido", unavailable: "no disponible", optuna: "Optuna",
};
const pipelineStatusLabels: Record<string, string> = { idle: "En espera", starting: "Iniciando", running: "En ejecución", cancelling: "Cancelando", completed: "Completado", failed: "Fallido", cancelled: "Cancelado" };
function label(text: string): string { if (translatedLabels[text]) return translatedLabels[text]; return text.replace(/_/g, " ").replace(/\b\w/g, (letter: string) => letter.toUpperCase()); }
function statusLabel(status: string): string { return pipelineStatusLabels[status] ?? status; }

function LanguageSwitch({ language, setLanguage }: { language: Language; setLanguage: (language: Language) => void }) {
  return <div className="language-switch" aria-label="Language / Idioma"><button className={language === "es" ? "selected" : ""} onClick={() => setLanguage("es")} type="button">ES</button><button className={language === "en" ? "selected" : ""} onClick={() => setLanguage("en")} type="button">EN</button></div>;
}

function ThemeButton({ theme, toggleTheme, language }: { theme: Theme; toggleTheme: () => void; language: Language }) {
  return <button className="theme-button" type="button" onClick={toggleTheme} aria-label={theme === "dark" ? t(language, "light") : t(language, "dark")} title={theme === "dark" ? t(language, "light") : t(language, "dark")}>{theme === "dark" ? "☀" : "☾"}</button>;
}

function Login({ onLogin, language, setLanguage, theme, toggleTheme }: { onLogin: () => void; language: Language; setLanguage: (language: Language) => void; theme: Theme; toggleTheme: () => void }) {
  const [username, setUsername] = useState("admin");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  async function submit(event: React.FormEvent) { event.preventDefault(); setError(""); try { await api.login(username, password); onLogin(); } catch (error) { setError((error as Error).message); } }
  return <main className="login"><div className="login-tools"><LanguageSwitch language={language} setLanguage={setLanguage} /><ThemeButton language={language} theme={theme} toggleTheme={toggleTheme} /></div><section className="card login-card"><div className="brand large">Riego IA<span>●</span><small>LABORATORIO DE AGRONOMÍA v2.1</small></div><h1>{t(language, "loginTitle")}</h1><p>{t(language, "loginDescription")}</p><form onSubmit={submit}><label>{t(language, "username")}<input value={username} onChange={event => setUsername(event.target.value)} required /></label><label>{t(language, "password")}<input type="password" value={password} onChange={event => setPassword(event.target.value)} required /></label>{error && <p className="error">{error}</p>}<button>{t(language, "login")}</button></form></section></main>;
}

function MetricCard({ label: title, value, detail, tone = "light" }: { label: string; value: string; detail: string; tone?: "light" | "green" }) {
  return <article className={`metric-card ${tone}`}><span>{title}</span><strong>{value}</strong><small>{detail}</small></article>;
}

function PipelineProgress({ pipeline, onStart, onCancel }: { pipeline: api.PipelineStatus; onStart: (fast: boolean, folds: number, trials: number) => void; onCancel: () => void }) {
  const active = ["starting", "running", "cancelling"].includes(pipeline.status);
  const current = Math.max(0, stages.findIndex(stage => stage[0] === pipeline.stage));
  const [fast, setFast] = useState(false);
  const [folds, setFolds] = useState(5);
  const [trials, setTrials] = useState(10);
  return <article className="card pipeline-panel"><div className="section-title"><div><span className="eyebrow">FLUJO CIENTÍFICO CONECTADO</span><h3>{pipeline.message}</h3><p>{pipeline.detail || "Cada etapa utiliza los artefactos de la etapa anterior."}</p></div><span className={`status-pill ${pipeline.status}`}>{statusLabel(pipeline.status)}</span></div><div className="progress-track"><div className="progress-value" style={{ width: `${Math.min(100, Math.max(0, pipeline.progress))}%` }} /></div><div className="progress-meta"><b>{Math.round(pipeline.progress)}%</b><span>Tiempo {duration(pipeline.elapsed_seconds)} · Tiempo restante {duration(pipeline.eta_seconds)}</span></div><div className="stage-line">{stages.map(([id, title], index) => <div className={`stage-dot ${index < current || pipeline.status === "completed" ? "done" : ""} ${index === current && active ? "current" : ""}`} key={id}><i>{index < current || pipeline.status === "completed" ? "✓" : index + 1}</i><small>{title}</small></div>)}</div>{pipeline.error && <p className="error notice">{pipeline.error}</p>}<div className="pipeline-settings"><label className="inline"><input type="checkbox" checked={fast} onChange={event => setFast(event.target.checked)} /> Modo rápido</label><label>Pliegues<select value={folds} onChange={event => setFolds(Number(event.target.value))} disabled={fast}><option value={3}>3 pliegues</option><option value={5}>5 pliegues</option><option value={7}>7 pliegues</option><option value={10}>10 pliegues</option></select></label><label>Pruebas de Optuna<input type="number" min={1} max={100} value={trials} onChange={event => setTrials(Number(event.target.value))} disabled={fast} /></label>{fast && <small>2 pliegues, 2 épocas y sin ajuste de hiperparámetros para una prueba rápida.</small>}</div><div className="panel-actions">{active ? <button className="danger" onClick={onCancel}>Cancelar proceso</button> : <button onClick={() => onStart(fast, fast ? 2 : folds, trials)}>{pipeline.status === "completed" ? "Repetir análisis" : "Iniciar entrenamiento"}</button>}</div></article>;
}

function DashboardPage({ dataset, pipeline, metrics, onStart, onCancel, go }: { dataset?: api.DatasetStatus; pipeline: api.PipelineStatus; metrics: Row[]; onStart: (fast: boolean, folds: number, trials: number) => void; onCancel: () => void; go: (page: Page) => void }) {
  const best = metrics[0] ?? {};
  const quality = dataset?.quality ?? {};
  return <section><div className="hero"><div><span className="breadcrumb">LABORATORIO / PANEL PRINCIPAL</span><h1>Sistema de Riego Inteligente con Redes Neuronales</h1><p>Comparación reproducible de MLP, DNN, RBF, CNN-MLP y LSTM-MLP para recomendar riego a partir de humedad del suelo, temperatura, humedad ambiental, MOI, tipo de suelo y etapa del cultivo.</p><div className="hero-actions"><button onClick={() => go("eda")}>Cargar conjunto de datos</button><button className="outline" onClick={() => go("training")}>Ver entrenamiento</button></div></div><div className="confidence"><span>MEJOR F1 ACTUAL</span><strong>{pct(best.f1)}</strong><small>{String(best.model ?? "Modelo pendiente")} persistido para inferencia</small></div></div><div className="metric-grid dashboard-metrics"><MetricCard label="Exactitud global" value={pct(best.accuracy)} detail="Conjunto de prueba" /><MetricCard label="Puntuación F1" value={num(best.f1)} detail="Balance entre precisión y sensibilidad" /><MetricCard label="Modelos activos" value={metrics.length ? String(metrics.length) : "—"} detail="3 clásicos + 2 híbridos" tone="green" /><MetricCard label="Registros útiles" value={quality.rows ? Number(quality.rows).toLocaleString() : "—"} detail={quality.rows_excluded ? `${Number(quality.rows_excluded).toLocaleString()} excluidos` : "Conjunto de datos pendiente"} /></div><PipelineProgress pipeline={pipeline} onStart={onStart} onCancel={onCancel} /><div className="grid three dashboard-cards"><button className="feature-card green-card" onClick={() => go("eda")}><span>01 · EDA</span><strong>Cargar y limpiar</strong><small>Validación de columnas, clases, faltantes y duplicados.</small><b>ABRIR EDA →</b></button><button className="feature-card blue-card" onClick={() => go("training")}><span>02 · ENTRENAMIENTO</span><strong>Comparar modelos</strong><small>Métricas, tiempos, ROC, matriz de confusión y modelo H5.</small><b>ABRIR ENTRENAMIENTO →</b></button><button className="feature-card purple-card" onClick={() => go("statistics")}><span>03 · RESULTADOS</span><strong>Decidir con evidencia</strong><small>Pruebas estadísticas, reportes y predicción individual o por lote.</small><b>VER RESULTADOS →</b></button></div></section>;
}

function EdaPage({ dataset, onRefresh, go }: { dataset?: api.DatasetStatus; onRefresh: () => void; go: (page: Page) => void }) {
  const [file, setFile] = useState<File>();
  const [message, setMessage] = useState("");
  async function upload() { if (!file) return; setMessage("Validando el esquema y limpiando el conjunto de datos…"); try { const result = await api.upload(file); setMessage(`Conjunto de datos ${String(result.filename)} cargado y validado. Ya puede pasar a Entrenamiento.`); onRefresh(); } catch (error) { setMessage((error as Error).message); } }
  const quality = dataset?.quality ?? {};
  const warnings = Array.isArray(quality.warnings) ? quality.warnings as unknown[] : dataset?.warnings ?? [];
  return <section><div className="section-heading"><span className="breadcrumb">01 / EDA</span><h2>Carga y limpieza del conjunto de datos</h2><p>Este módulo se limita a preparar los datos. Las tablas de modelos, figuras, curvas ROC y pruebas estadísticas aparecen en las etapas posteriores.</p></div><div className="eda-layout"><article className="upload-zone card"><span className="upload-icon">↥</span><h3>Subir nuevo conjunto de datos</h3><p>Seleccione manualmente el archivo CSV, XLSX o XLS del experimento.</p><input type="file" accept=".csv,.xlsx,.xls" onChange={event => setFile(event.target.files?.[0])} /><button onClick={() => void upload()} disabled={!file}>Validar y limpiar</button>{message && <p className="notice">{message}</p>}</article><article className="card schema-card"><h3>Lista de comprobación de limpieza</h3>{["Alias de columnas normalizados", "Tipos numéricos convertidos", "Faltantes preparados para imputación", "result=2 excluido del estudio binario", "Duplicados reportados, no inventados"].map(item => <div className="schema-row" key={item}>{item}<span>✓</span></div>)}<small>La clase result=2 se registra como exceso de agua y no se transforma en riego.</small></article></div><article className="card validation-card"><div className="section-title"><div><span className="eyebrow">VALIDACIÓN DE ENTRADA</span><h3>{dataset?.filename ?? "Esperando conjunto de datos"}</h3></div><span className={`status-pill ${dataset?.available ? "completed" : "idle"}`}>{dataset?.available ? "limpio" : "pendiente"}</span></div><div className="metric-grid four"><MetricCard label="Registros útiles" value={quality.rows ? Number(quality.rows).toLocaleString() : "—"} detail="Después de limpieza" /><MetricCard label="Exceso de agua" value={quality.rows_excluded ? Number(quality.rows_excluded).toLocaleString() : "0"} detail="Filas excluidas" /><MetricCard label="Duplicados" value={quality.duplicates != null ? String(quality.duplicates) : "—"} detail="Detectados" /><MetricCard label="Clases objetivo" value={quality.class_distribution ? "0 / 1" : "—"} detail="Clasificación binaria" /></div>{warnings.length ? <div className="warning-list">{warnings.map((warning, index) => <p key={index}>• {String(warning)}</p>)}</div> : <p className="muted">Cargue un archivo para ver las decisiones de limpieza.</p>}<button className="next-button" disabled={!dataset?.available} onClick={() => go("training")}>Continuar a Entrenamiento →</button></article></section>;
}

const modelNames = ["MLP", "DNN", "RBF", "CNN_MLP", "LSTM_MLP"];
const soilOptions = [["Suelo negro", "Black Soil"], ["Suelo aluvial", "Alluvial Soil"], ["Suelo arenoso", "Sandy Soil"], ["Suelo rojo", "Red Soil"], ["Suelo arcilloso", "Clay Soil"], ["Suelo franco", "Loam Soil"], ["Suelo calcáreo", "Chalky Soil"]];
const cropStageOptions = [["Germinación", "Germination"], ["Etapa de plántula", "Seedling Stage"], ["Crecimiento vegetativo / desarrollo de raíz o tubérculo", "Vegetative Growth / Root or Tuber Development"], ["Floración", "Flowering"], ["Polinización", "Pollination"], ["Formación de fruto, grano o bulbo", "Fruit/Grain/Bulb Formation"], ["Maduración", "Maturation"], ["Cosecha", "Harvest"]];
const resultColumns = ["model", "accuracy", "precision", "recall", "specificity", "f1", "roc_auc", "training_seconds", "inference_p95_seconds"];

function ResultsTable({ rows, columns = resultColumns }: { rows: Row[]; columns?: string[] }) {
  return <div className="table-wrap"><table><thead><tr>{columns.map(column => <th key={column}>{label(column)}</th>)}</tr></thead><tbody>{rows.map((row, index) => <tr className={index === 0 ? "highlight" : ""} key={index}>{columns.map(column => <td key={column}>{column === "model" || column.startsWith("model_") ? String(row[column] ?? "—") : num(row[column], column.includes("p_value") ? 5 : 4)}</td>)}</tr>)}</tbody></table></div>;
}

function FigureCard({ figure }: { figure: Figure }) {
  const [preview, setPreview] = useState("");
  const [error, setError] = useState("");
  useEffect(() => { let url = ""; void api.downloadFigure(figure.filename).then(blob => { url = URL.createObjectURL(blob); setPreview(url); }).catch(error => setError((error as Error).message)); return () => { if (url) URL.revokeObjectURL(url); }; }, [figure.filename]);
  async function download() { const blob = await api.downloadFigure(figure.filename); const url = URL.createObjectURL(blob); const anchor = document.createElement("a"); anchor.href = url; anchor.download = figure.filename; anchor.click(); URL.revokeObjectURL(url); }
  return <article className="figure-card"><div className="figure-card-head"><strong>{label(figure.filename.replace(/\.png$/i, ""))}</strong><span>{Math.round(figure.size / 1024)} KB</span></div>{preview ? <img src={preview} alt={`Figura ${figure.filename}`} /> : <div className="figure-loading">{error || "Cargando figura…"}</div>}<button onClick={() => void download()}>Descargar figura</button></article>;
}

function FigureGallery({ figures }: { figures: Figure[] }) { return <div className="figure-gallery">{figures.length ? figures.map(figure => <FigureCard figure={figure} key={figure.filename} />) : <p className="muted">Las figuras aparecerán cuando finalice el entrenamiento.</p>}</div>; }

function TrainingPage({ pipeline, metrics, figures, metadata, onStart, onCancel }: { pipeline: api.PipelineStatus; metrics: Row[]; figures: Figure[]; metadata: Row; onStart: (fast: boolean, folds: number, trials: number) => void; onCancel: () => void }) {
  const bestName = String(pipeline.result?.model_name ?? metrics[0]?.model ?? metadata.model_name ?? "—");
  const best = metrics.find(row => String(row.model) === bestName) ?? metrics[0] ?? {};
  const history = (pipeline.history ?? []).slice(-8).reverse() as Row[];
  return <section><div className="section-heading"><span className="breadcrumb">02 / ENTRENAMIENTO</span><h2>Entrenamiento y comparación de modelos</h2><p>Aquí se concentran las métricas, tiempos de proceso, validación, figuras de evaluación y el modelo H5 listo para predicción.</p></div><PipelineProgress pipeline={pipeline} onStart={onStart} onCancel={onCancel} /><div className="model-cards">{modelNames.map(name => { const row = metrics.find(item => item.model === name) ?? {}; const hybrid = name.includes("CNN") || name.includes("LSTM"); return <article className={`model-card ${bestName === name ? "selected" : ""}`} key={name}><span className={hybrid ? "tag hybrid" : "tag classic"}>{hybrid ? "HÍBRIDO" : "CLÁSICO"}</span><h3>{name}</h3><small>{name === "MLP" ? "Perceptrón multicapa" : name === "DNN" ? "Red neuronal profunda" : name === "RBF" ? "Función de base radial" : name === "CNN_MLP" ? "Red convolucional + MLP" : "Memoria larga + MLP"}</small><div className="model-line"><i style={{ width: `${row.f1 ? Number(row.f1) * 100 : 0}%` }} /></div><b>{pct(row.f1)} F1</b>{bestName === name && <span className="best-badge">★ MEJOR</span>}</article>; })}</div><div className="metric-grid four"><MetricCard label="Mejor exactitud" value={pct(best.accuracy)} detail={bestName} /><MetricCard label="Mejor ROC-AUC" value={num(best.roc_auc)} detail="Área bajo la curva" /><MetricCard label="Tiempo de entrenamiento" value={duration(Number(best.training_seconds))} detail="Modelo seleccionado" /><MetricCard label="Inferencia P95" value={`${num(best.inference_p95_seconds, 4)} s`} detail="Latencia por fila" tone="green" /></div><article className="card table-card"><div className="section-title"><div><span className="eyebrow">RESULTADOS COMPARATIVOS</span><h3>Tabla comparativa completa</h3></div><span className="muted">Estadísticos · tiempo · latencia · estabilidad de validación</span></div><ResultsTable rows={metrics} /></article><div className="grid two"><article className="card model-save"><div><span className="eyebrow">MEJOR MODELO GUARDADO</span><h3>{bestName} · best_irrigation_model.h5</h3><p>El archivo H5 y el preprocesador se guardan en la carpeta de artefactos y se consumen sin volver a entrenar.</p></div><button onClick={() => void api.downloadModel()}>Descargar .h5</button></article><article className="card log-card"><div className="section-title"><div><span className="eyebrow">REGISTRO EN VIVO</span><h3>Últimos eventos</h3></div></div>{history.length ? history.map((item, index) => <p key={index}><b>{String(item.at ?? "")}</b> {String(item.message ?? "")} <small>{String(item.detail ?? "")}</small></p>) : <p className="muted">El registro aparecerá al iniciar el flujo.</p>}</article></div><article className="card figures-card"><div className="section-title"><div><span className="eyebrow">EVIDENCIA DE EVALUACIÓN</span><h3>Matriz de confusión, ROC y mapas de calor</h3></div><span className="muted">Figuras generadas sobre el conjunto de prueba</span></div><FigureGallery figures={figures} /></article></section>;
}

function CrossValidationPage({ rows, onStart }: { rows: Row[]; onStart: (fast: boolean, folds: number, trials: number) => void }) {
  const folds = new Set(rows.map(row => String(row.fold))).size;
  const mean = rows.length ? rows.reduce((sum, row) => sum + Number(row.f1 ?? 0), 0) / rows.length : 0;
  const std = rows.length > 1 ? Math.sqrt(rows.reduce((sum, row) => sum + (Number(row.f1 ?? 0) - mean) ** 2, 0) / (rows.length - 1)) : 0;
  return <section><div className="section-heading"><span className="breadcrumb">03 / VALIDACIÓN CRUZADA</span><h2>Validación cruzada estratificada</h2><p>Evalúa estabilidad, variabilidad y generalización. Use 5 pliegues para activar Friedman de forma completa.</p></div><div className="metric-grid four"><MetricCard label="F1 medio" value={num(mean)} detail="Promedio de modelos y pliegues" /><MetricCard label="Desviación F1" value={num(std)} detail="Variabilidad entre pliegues" /><MetricCard label="Pliegues calculados" value={folds ? String(folds) : "—"} detail="Particiones estratificadas" tone="green" /><MetricCard label="Filas evaluadas" value={rows.length ? String(rows.length) : "—"} detail="Registros de validación" /></div><article className="card action-card"><div><h3>Ejecutar una nueva validación</h3><p>La ejecución científica usa 5 pliegues y mantiene el conjunto de prueba separado.</p></div><button onClick={() => onStart(false, 5, 10)}>Ejecutar 5 pliegues</button></article><article className="card table-card"><div className="section-title"><div><span className="eyebrow">DETALLE POR PLIEGUE</span><h3>Detalle por modelo y pliegue</h3></div></div><ResultsTable rows={rows} columns={["model", "fold", "accuracy", "precision", "recall", "f1", "roc_auc", "training_seconds"]} /></article></section>;
}

function TuningPage({ tuning, onStart }: { tuning: Row; onStart: (fast: boolean, folds: number, trials: number) => void }) {
  const [model, setModel] = useState("Todos los modelos");
  const [metric, setMetric] = useState("f1");
  const [trials, setTrials] = useState(20);
  const entries = Object.entries(tuning).filter(([name]) => model === "Todos los modelos" || name === model);
  return <section><div className="section-heading"><span className="breadcrumb">04 / HIPERPARÁMETROS</span><h2>Optimización de hiperparámetros</h2><p>Configure el objetivo, el modelo y el número de pruebas. El estudio completo se ejecuta sin tocar el conjunto de prueba.</p></div><div className="tuning-layout"><article className="card tuning-controls"><span className="eyebrow">PANEL DE CONFIGURACIÓN</span><label>Modelo a optimizar<select value={model} onChange={event => setModel(event.target.value)}><option>Todos los modelos</option>{modelNames.map(name => <option key={name}>{name}</option>)}</select></label><label>Métrica objetivo<select value={metric} onChange={event => setMetric(event.target.value)}><option value="f1">Puntuación F1</option><option value="roc_auc">ROC-AUC</option><option value="balanced_accuracy">Exactitud balanceada</option></select></label><label>Número de pruebas<input type="number" min={1} max={100} value={trials} onChange={event => setTrials(Number(event.target.value))} /></label><button onClick={() => onStart(false, 5, trials)}>Iniciar estudio de optimización</button><small>Objetivo configurado: {label(metric)}. Se optimizarán los cinco modelos para mantener una comparación justa.</small></article><article className="card tuning-history"><div className="section-title"><div><span className="eyebrow">HISTORIAL DE OPTIMIZACIÓN</span><h3>Configuraciones encontradas</h3></div><span className="status-pill completed">guardado</span></div>{entries.length ? entries.map(([name, value]) => { const row = asRow(value); return <div className="tuning-row" key={name}><div><strong>{name}</strong><small>Motor: {label(String(row.backend ?? "no disponible"))} · {String(row.trials ?? 0)} pruebas</small></div><span>{row.best_value != null ? num(row.best_value, 4) : "—"}</span></div>; }) : <p className="muted">Ejecute el flujo completo para llenar el historial de optimización.</p>}</article></div><article className="card parameter-grid"><h3>Importancia y parámetros guardados</h3>{entries.map(([name, value]) => { const row = asRow(value); const params = asRow(row.best_params); return <div className="parameter-block" key={name}><b>{name}</b>{Object.entries(params).length ? Object.entries(params).map(([key, parameter]) => <span key={key}><i style={{ width: `${Math.min(100, Math.abs(Number(parameter) || 0) * 100)}%` }} />{label(key)} <strong>{String(parameter)}</strong></span>) : <small>Sin parámetros: el modo rápido omitió la optimización.</small>}</div>; })}</article></section>;
}

function InterpretationList({ rows }: { rows: Row[] }) { return <div className="interpretation-list">{rows.length ? rows.map((row, index) => <div className={`interpretation-item ${row.significant ? "significant" : ""}`} key={index}><strong>{String(row.model_a ?? "") } vs {String(row.model_b ?? "")}</strong><span>{String(row.interpretation_es ?? "Sin interpretación disponible.")}</span></div>) : <p className="muted">No hay comparaciones calculadas todavía.</p>}</div>; }

function StatisticsPage({ statistics }: { statistics: Row }) {
  const friedman = asRow(statistics.friedman);
  const tRows = asRows(statistics.paired_t);
  const wilcoxon = asRows(statistics.wilcoxon ?? statistics.pairwise);
  const significantT = tRows.filter(row => Boolean(row.significant)).length;
  const significantW = wilcoxon.filter(row => Boolean(row.significant)).length;
  const formulas = asRow(statistics.formulas_es);
  return <section><div className="section-heading"><span className="breadcrumb">05 / PRUEBAS ESTADÍSTICAS</span><h2>Pruebas estadísticas robustas</h2><p>Resultados calculados sobre pliegues pareados: t de Student pareada, Friedman, Wilcoxon y McNemar, con valor p ajustado por Holm.</p></div><div className="metric-grid four"><MetricCard label="t de Student pareada" value={tRows.length ? `${significantT}/${tRows.length}` : "—"} detail="Comparaciones significativas" /><MetricCard label="Valor p de Friedman" value={friedman.p_value != null ? num(friedman.p_value, 5) : "—"} detail={friedman.available === false ? "Requiere 3 o más pliegues" : "Contraste global"} /><MetricCard label="Wilcoxon + Holm" value={wilcoxon.length ? `${significantW}/${wilcoxon.length}` : "—"} detail="Comparaciones no paramétricas" tone="green" /><MetricCard label="Pliegues usados" value={statistics.n_folds != null ? String(statistics.n_folds) : "—"} detail="Unidad pareada" /></div><article className="card interpretation-card"><span className="eyebrow">INTERPRETACIÓN AUTOMÁTICA</span><h3>{friedman.significant ? "Hay evidencia de diferencias globales" : friedman.available === false ? "Friedman pendiente de pliegues suficientes" : "No hay evidencia global suficiente"}</h3><p>{String(statistics.interpretation_es ?? "El análisis se mostrará después de completar el entrenamiento científico.")}</p><div className="formula-grid"><div><strong>t pareada</strong><span>{String(formulas.paired_t ?? "dᵢ = F1A − F1B; t = media(d) / (sd(d) / √n)")}</span></div><div><strong>Friedman</strong><span>{String(formulas.friedman ?? "Rangos por pliegue; contraste global con gl = k − 1")}</span></div><div><strong>Wilcoxon</strong><span>{String(formulas.wilcoxon ?? "Rangos de |dᵢ|; W es la menor suma de rangos")}</span></div></div></article><div className="grid two"><article className="card table-card"><div className="section-title"><div><span className="eyebrow">t PAREADA</span><h3>t de Student pareada</h3></div><span className="muted">Media, IC95%, gl y Holm</span></div><ResultsTable rows={tRows} columns={["model_a", "model_b", "n", "mean_difference", "ci95_low", "ci95_high", "t_statistic", "p_value", "p_value_holm", "cohen_d_paired"]} /><InterpretationList rows={tRows} /></article><article className="card table-card"><div className="section-title"><div><span className="eyebrow">NO PARAMÉTRICA</span><h3>Wilcoxon con Holm</h3></div><span className="muted">Rangos y efecto pareado</span></div><ResultsTable rows={wilcoxon} columns={["model_a", "model_b", "n_nonzero", "positive_rank_sum", "negative_rank_sum", "statistic", "effect", "p_value", "p_value_holm"]} /><InterpretationList rows={wilcoxon} /></article></div><article className="card table-card"><div className="section-title"><div><span className="eyebrow">PRUEBA GLOBAL</span><h3>Friedman y comparaciones adicionales</h3></div></div><div className="stat-result"><strong>Friedman χ² = {num(friedman.statistic, 4)}</strong><span>gl = {String(friedman.degrees_of_freedom ?? "—")} · W de Kendall = {num(friedman.kendall_w, 4)} · valor p = {num(friedman.p_value, 5)}</span><p>{String(friedman.interpretation_es ?? "No hay interpretación disponible.")}</p></div><p className="muted">McNemar: {Array.isArray(statistics.mcnemar) && statistics.mcnemar.length ? "resultado disponible en el informe." : "no calculado para esta ejecución."}</p></article></section>;
}

function PredictionPage({ metadata }: { metadata: Row }) {
  const [mode, setMode] = useState<"individual" | "batch">("individual");
  const [form, setForm] = useState({ temperature: "31.5", humidity: "48", moi: "35", soil_type: "Black Soil", crop_stage: "Germination", crop_id: "" });
  const [result, setResult] = useState<api.Prediction>();
  const [history, setHistory] = useState<api.Prediction[]>([]);
  const [batchFile, setBatchFile] = useState<File>();
  const [batchRows, setBatchRows] = useState<Row[]>([]);
  const [error, setError] = useState("");
  async function predict() { try { const prediction = await api.predict({ ...form, temperature: Number(form.temperature), humidity: Number(form.humidity), moi: Number(form.moi), crop_id: form.crop_id || undefined }); setResult(prediction); setHistory(current => [prediction, ...current].slice(0, 5)); setError(""); } catch (error) { setError((error as Error).message); } }
  async function predictBatch() { if (!batchFile) return; try { const response = await api.predictBatch(batchFile); setBatchRows(response.rows); setError(""); } catch (error) { setError((error as Error).message); } }
  function downloadBatch() { if (!batchRows.length) return; const columns = Object.keys(batchRows[0]); const csv = [columns.join(","), ...batchRows.map(row => columns.map(column => JSON.stringify(row[column] ?? "")).join(","))].join("\n"); const url = URL.createObjectURL(new Blob([csv], { type: "text/csv;charset=utf-8" })); const anchor = document.createElement("a"); anchor.href = url; anchor.download = "predicciones_riego.csv"; anchor.click(); URL.revokeObjectURL(url); }
  const irrigationCount = batchRows.filter(row => Number(row.predicted_class) === 1).length;
  return <section><div className="section-heading"><span className="breadcrumb">06 / PREDICCIÓN</span><h2>Predicción operacional</h2><p>Consume el modelo H5 y el preprocesador guardado. Puede evaluar una parcela o cargar muchas filas sin reentrenar.</p></div><div className="tabs"><button className={mode === "individual" ? "selected-tab" : ""} onClick={() => setMode("individual")}>Predicción individual</button><button className={mode === "batch" ? "selected-tab" : ""} onClick={() => setMode("batch")}>Predicción por lote</button></div>{mode === "individual" ? <div className="prediction-layout"><form className="card form-grid" onSubmit={event => { event.preventDefault(); void predict(); }}><div className="form-section-title"><span className="eyebrow">SENSORES Y CONTEXTO</span><small>Modelo: {String(metadata.model_name ?? "persistido")}</small></div>{Object.entries(form).map(([key, value]) => <label key={key}>{label(key)}{key === "soil_type" ? <select value={value} onChange={event => setForm({ ...form, [key]: event.target.value })}>{soilOptions.map(([title, option]) => <option value={option} key={option}>{title}</option>)}</select> : key === "crop_stage" ? <select value={value} onChange={event => setForm({ ...form, [key]: event.target.value })}>{cropStageOptions.map(([title, option]) => <option value={option} key={option}>{title}</option>)}</select> : <input value={value} onChange={event => setForm({ ...form, [key]: event.target.value })} required={key !== "crop_id"} />}</label>)}<button>Calcular recomendación</button>{error && <p className="error">{error}</p>}</form><article className="card prediction-result">{result ? <><span className="eyebrow">RESULTADO DE INFERENCIA</span><h3>{result.recommendation}</h3><div className="probability">{pct(result.probability_irrigation)}</div><div className="confidence-meter"><i style={{ width: `${result.probability_irrigation * 100}%` }} /></div><p>Probabilidad de requerir riego · umbral {pct(result.threshold)} · clase {result.predicted_class}</p><div className="result-facts"><span>Modelo<strong>{result.model_name}</strong></span><span>Versión<strong>{result.model_version}</strong></span><span>Decisión<strong>{result.predicted_class ? "Activar revisión" : "No regar"}</strong></span></div></> : <p>Introduzca los datos agronómicos para obtener una recomendación explicable.</p>}</article></div> : <article className="card batch-card"><span className="eyebrow">PREDICCIÓN POR LOTE</span><h3>Predicción masiva sin columna result</h3><p>Suba las mismas columnas de entrada del conjunto de datos. El sistema devolverá probabilidad, clase y recomendación por fila.</p><input type="file" accept=".csv,.xlsx,.xls" onChange={event => setBatchFile(event.target.files?.[0])} /><div className="panel-actions"><button onClick={() => void predictBatch()} disabled={!batchFile}>Procesar lote</button><button className="outline dark-text" onClick={downloadBatch} disabled={!batchRows.length}>Descargar resultados CSV</button></div>{batchRows.length > 0 && <><div className="metric-grid three"><MetricCard label="Filas procesadas" value={String(batchRows.length)} detail="Entradas válidas" /><MetricCard label="Requieren riego" value={String(irrigationCount)} detail="Clase predicha 1" tone="green" /><MetricCard label="No requieren" value={String(batchRows.length - irrigationCount)} detail="Clase predicha 0" /></div><ResultsTable rows={batchRows.slice(0, 50)} columns={["temperature", "humidity", "moi", "probability_irrigation", "predicted_class", "recommendation"]} /></>}</article>}{mode === "individual" && <article className="card history-card"><div className="section-title"><div><span className="eyebrow">HISTORIAL DE SESIÓN</span><h3>Últimas predicciones</h3></div></div>{history.length ? history.map((item, index) => <div className="history-row" key={index}><span>{item.recommendation}</span><b>{pct(item.probability_irrigation)}</b><small>{item.model_name}</small></div>) : <p className="muted">No hay predicciones en esta sesión.</p>}</article>}</section>;
}

function ReportsPage({ reports, statistics, metrics, metadata, figures }: { reports: Report[]; statistics: Row; metrics: Row[]; metadata: Row; figures: Figure[] }) {
  const [downloading, setDownloading] = useState("");
  async function download(filename: string) { setDownloading(filename); try { const blob = await api.downloadReport(filename); const url = URL.createObjectURL(blob); const anchor = document.createElement("a"); anchor.href = url; anchor.download = filename; anchor.click(); URL.revokeObjectURL(url); } finally { setDownloading(""); } }
  const friedman = asRow(statistics.friedman);
  return <section><div className="section-heading"><span className="breadcrumb">07 / REPORTES</span><h2>Reportes científicos y entregables</h2><p>Un centro de resultados para auditar el conjunto de datos, comparar los modelos, interpretar las pruebas y descargar la evidencia.</p></div><div className="metric-grid four"><MetricCard label="Modelo seleccionado" value={String(metadata.model_name ?? "—")} detail="Guardado como H5" tone="green" /><MetricCard label="Modelos comparados" value={String(metrics.length || "—")} detail="Clásicos e híbridos" /><MetricCard label="Friedman" value={friedman.p_value != null ? num(friedman.p_value, 5) : "—"} detail="Prueba global" /><MetricCard label="Figuras incluidas" value={String(figures.length)} detail="Preparación y evaluación" /></div><div className="report-layout"><article className="card report-center"><div className="section-title"><div><span className="eyebrow">EXPORTACIÓN EN VARIOS FORMATOS</span><h3>Descargar análisis completo</h3></div><span className="status-pill completed">listo</span></div>{reports.length ? reports.map(report => <div className="report-row" key={report.filename}><div><strong>{report.filename}</strong><small>{Math.round(report.size / 1024)} KB · tablas · figuras · interpretación</small></div><button onClick={() => void download(report.filename)} disabled={downloading === report.filename}>{downloading === report.filename ? "Preparando…" : "Descargar"}</button></div>) : <p className="muted">Ejecute el entrenamiento para generar PDF, Word y Excel.</p>}</article><article className="card report-checklist"><h3>Contenido del informe</h3>{["Calidad y limpieza del conjunto de datos", "Tabla de métricas y tiempos", "Validación cruzada por pliegue", "t de Student pareada", "Friedman y Wilcoxon + Holm", "Matriz de confusión, ROC y mapas de calor", "Modelo H5 y metadatos de inferencia", "Limitaciones e interpretación en español"].map(item => <p key={item}>✓ {item}</p>)}</article></div><article className="card figures-card"><div className="section-title"><div><span className="eyebrow">FIGURAS PARA REVISIÓN</span><h3>Vista previa de la evidencia</h3></div></div><FigureGallery figures={figures} /></article></section>;
}

type ChatMessage = { id: number; role: "assistant" | "user"; text: string };

function assistantReply(question: string, language: Language, pipeline: api.PipelineStatus, dataset?: api.DatasetStatus): string {
  const q = question.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
  const available = dataset?.available ? (language === "es" ? "El dataset está disponible y validado." : "The dataset is available and validated.") : (language === "es" ? "Todavía no hay un dataset validado." : "There is no validated dataset yet.");
  const status = language === "es" ? `El estado actual del flujo es «${statusLabel(pipeline.status)}».` : `The current pipeline status is “${pipeline.status}”.`;
  if (q.includes("funciona") || q.includes("flujo") || q.includes("pipeline") || q.includes("how does") || q.includes("how it works")) {
    return language === "es" ? `El flujo es secuencial: 1) EDA carga y limpia el dataset, 2) Entrenamiento compara cinco modelos, 3) Validación cruzada mide la generalización, 4) Hiperparámetros optimiza configuraciones, 5) Pruebas estadísticas comparan resultados, 6) Reportes exporta la evidencia y 7) Predicción consume el mejor H5. ${status}` : `The workflow is sequential: 1) EDA uploads and cleans the dataset, 2) Training compares five models, 3) Cross-validation measures generalization, 4) Hyperparameters optimizes configurations, 5) Statistical tests compare results, 6) Reports exports the evidence, and 7) Prediction consumes the best H5 model. ${status}`;
  }
  if (q.includes("dataset") || q.includes("datos") || q.includes("cargar") || q.includes("upload") || q.includes("eda")) {
    return language === "es" ? `${available} Ve a EDA, selecciona un archivo CSV/XLSX/XLS y pulsa «Validar y limpiar». El sistema normaliza columnas, revisa faltantes y duplicados, y excluye result=2 del estudio binario.` : `${available} Go to EDA, select a CSV/XLSX/XLS file, and click “Validate and clean”. The system normalizes columns, checks missing values and duplicates, and excludes result=2 from the binary study.`;
  }
  if (q.includes("entren") || q.includes("modelo") || q.includes("training") || q.includes("model")) {
    return language === "es" ? `${status} En Entrenamiento se ejecutan MLP, DNN, RBF, CNN-MLP y LSTM-MLP. Se comparan exactitud, F1, ROC-AUC, tiempos, matriz de confusión y curvas ROC. El mejor modelo se guarda en H5 para no reentrenar.` : `${status} Training runs MLP, DNN, RBF, CNN-MLP, and LSTM-MLP. It compares accuracy, F1, ROC-AUC, timing, confusion matrix, and ROC curves. The best model is saved as H5 so it is not retrained.`;
  }
  if (q.includes("t student") || q.includes("friedman") || q.includes("wilcoxon") || q.includes("estadistic") || q.includes("statistical") || q.includes("test")) {
    return language === "es" ? "Las pruebas usan resultados pareados por pliegue: t de Student pareada compara medias, Friedman contrasta todos los modelos globalmente y Wilcoxon compara pares sin asumir normalidad. El sistema muestra estadístico, valor p, Holm, tamaño de efecto e interpretación." : "The tests use fold-paired results: paired Student’s t compares means, Friedman provides a global comparison, and Wilcoxon compares pairs without assuming normality. The system shows the statistic, p-value, Holm adjustment, effect size, and interpretation.";
  }
  if (q.includes("predic") || q.includes("riego") || q.includes("prediction") || q.includes("irrigation")) {
    return language === "es" ? "En Predicción puedes evaluar una parcela con temperatura, humedad, MOI, suelo y etapa del cultivo, o procesar un CSV/XLSX por lote. La recomendación usa el modelo H5 guardado y muestra probabilidad, clase y decisión." : "In Prediction you can evaluate one plot using temperature, humidity, MOI, soil, and crop stage, or process a CSV/XLSX batch. The recommendation uses the saved H5 model and shows probability, class, and decision.";
  }
  if (q.includes("reporte") || q.includes("report") || q.includes("pdf") || q.includes("excel") || q.includes("word")) {
    return language === "es" ? "Reportes permite descargar PDF, Word y Excel con calidad de datos, métricas, validación cruzada, pruebas t/Friedman/Wilcoxon, figuras e interpretación científica." : "Reports lets you download PDF, Word, and Excel files with data quality, metrics, cross-validation, t/Friedman/Wilcoxon tests, figures, and scientific interpretation.";
  }
  if (q.includes("oscuro") || q.includes("claro") || q.includes("dark") || q.includes("light") || q.includes("idioma") || q.includes("language")) {
    return language === "es" ? "Usa los controles ES/EN y ☾/☀ en la barra superior. La preferencia se guarda automáticamente en este navegador." : "Use the ES/EN and ☾/☀ controls in the top bar. Your preference is saved automatically in this browser.";
  }
  return language === "es" ? `Puedo ayudarte con EDA, entrenamiento, validación cruzada, hiperparámetros, pruebas estadísticas, reportes y predicción. ${status} Pregúntame, por ejemplo: «¿Cómo interpreto Friedman?»` : `I can help with EDA, training, cross-validation, hyperparameters, statistical tests, reports, and prediction. ${status} Try asking: “How do I interpret Friedman?”`;
}

function ChatBot({ language, pipeline, dataset }: { language: Language; pipeline: api.PipelineStatus; dataset?: api.DatasetStatus }) {
  const [open, setOpen] = useState(false);
  const [input, setInput] = useState("");
  const [messages, setMessages] = useState<ChatMessage[]>([{ id: 1, role: "assistant", text: t(language, "chatGreeting") }]);
  const quickQuestions = [t(language, "quickHow"), t(language, "quickData"), t(language, "quickStats"), t(language, "quickPrediction")];
  function send(rawQuestion: string) {
    const question = rawQuestion.trim();
    if (!question) return;
    setMessages(current => [...current, { id: Date.now(), role: "user", text: question }, { id: Date.now() + 1, role: "assistant", text: assistantReply(question, language, pipeline, dataset) }]);
    setInput("");
  }
  function reset() { setMessages([{ id: Date.now(), role: "assistant", text: t(language, "chatGreeting") }]); }
  return <div className={`chatbot ${open ? "is-open" : ""}`}><button className="chat-launcher" type="button" onClick={() => setOpen(!open)} aria-label={open ? t(language, "chatClose") : t(language, "chatOpen")}><span>{open ? "×" : "✦"}</span><b>{open ? t(language, "chatClose") : "IA"}</b></button>{open && <section className="chat-panel" aria-label={t(language, "chatTitle")}><header className="chat-header"><div><strong>{t(language, "chatTitle")}</strong><small>{t(language, "assistantHint")}</small></div><button type="button" onClick={reset} title={t(language, "chatReset")}>↺</button></header><div className="chat-messages" aria-live="polite">{messages.map(message => <div className={`chat-message ${message.role}`} key={message.id}>{message.role === "assistant" && <span className="chat-avatar">IA</span>}<p>{message.text}</p></div>)}</div><div className="chat-quick-actions">{quickQuestions.map(question => <button type="button" key={question} onClick={() => send(question)}>{question}</button>)}</div><form className="chat-input" onSubmit={event => { event.preventDefault(); send(input); }}><input value={input} onChange={event => setInput(event.target.value)} placeholder={t(language, "chatPlaceholder")} aria-label={t(language, "chatPlaceholder")} /><button type="submit">{t(language, "send")}</button></form></section>}</div>;
}

function App() {
  const [logged, setLogged] = useState(Boolean(sessionStorage.getItem("irrigation_token")));
  const [language, setLanguage] = useState<Language>(() => (localStorage.getItem("irrigation_language") as Language | null) ?? "es");
  const [theme, setTheme] = useState<Theme>(() => (localStorage.getItem("irrigation_theme") as Theme | null) ?? "light");
  const [page, setPage] = useState<Page>("dashboard");
  const [dataset, setDataset] = useState<api.DatasetStatus>();
  const [pipeline, setPipeline] = useState<api.PipelineStatus>(initialPipeline);
  const [metrics, setMetrics] = useState<Row[]>([]);
  const [cv, setCv] = useState<Row[]>([]);
  const [tuning, setTuning] = useState<Row>({});
  const [statistics, setStatistics] = useState<Row>({});
  const [metadata, setMetadata] = useState<Row>({});
  const [figures, setFigures] = useState<Figure[]>([]);
  const [reports, setReports] = useState<Report[]>([]);
  const refresh = async () => { try { const [dataResult, pipelineResult, metricResult, cvResult, tuningResult, statisticsResult, figureResult] = await Promise.all([api.status(), api.trainStatus(), api.metrics(), api.cv(), api.tuning(), api.statistics(), api.figures()]); setDataset(dataResult); setPipeline(pipelineResult); setMetrics(metricResult.models); setCv(cvResult.rows); setTuning(tuningResult); setStatistics(statisticsResult); setFigures(figureResult.figures); try { setMetadata(await api.modelMetadata()); } catch { setMetadata({}); } try { setReports((await api.reports()).reports); } catch { setReports([]); } } catch (error) { if ((error as Error).message === "AUTH_EXPIRED") { api.logout(); setLogged(false); } } };
  useEffect(() => { if (logged) void refresh(); }, [logged]);
  useEffect(() => { if (!logged) return; const timer = window.setInterval(() => void refresh(), 2500); return () => window.clearInterval(timer); }, [logged]);
  useEffect(() => { localStorage.setItem("irrigation_language", language); document.documentElement.lang = language; }, [language]);
  useEffect(() => { localStorage.setItem("irrigation_theme", theme); document.documentElement.dataset.theme = theme; }, [theme]);
  async function start(fast: boolean, folds: number, trials: number) { try { await api.runPipeline(fast, folds, trials); setPage("training"); await refresh(); } catch (error) { window.alert((error as Error).message); } }
  async function cancel() { try { await api.cancelPipeline(); await refresh(); } catch (error) { window.alert((error as Error).message); } }
  if (!logged) return <Login onLogin={() => setLogged(true)} language={language} setLanguage={setLanguage} theme={theme} toggleTheme={() => setTheme(current => current === "dark" ? "light" : "dark")} />;
  const nav: [Page, string][] = [["dashboard", t(language, "navDashboard")], ["eda", t(language, "navEda")], ["training", t(language, "navTraining")], ["cv", t(language, "navCv")], ["tuning", t(language, "navTuning")], ["statistics", t(language, "navStatistics")], ["reports", t(language, "navReports")], ["predict", t(language, "navPredict")]];
  const toggleTheme = () => setTheme(current => current === "dark" ? "light" : "dark");
  return <div className="app-shell"><aside className="sidebar"><div className="lab-brand"><strong>Riego IA</strong><span>LABORATORIO DE AGRONOMÍA v2.1</span></div><div className="nav-label">{language === "es" ? "MÓDULOS PRINCIPALES" : "MAIN MODULES"}</div><nav>{nav.map(([id, title]) => { const locked = ["cv", "tuning", "statistics", "reports", "predict"].includes(id) && pipeline.status !== "completed"; return <button key={id} className={page === id ? "active" : ""} disabled={locked} onClick={() => setPage(id)}><i>{id === "dashboard" ? "▦" : id === "eda" ? "↥" : id === "training" ? "◉" : id === "cv" ? "↝" : id === "tuning" ? "⌘" : id === "statistics" ? "∑" : id === "reports" ? "▥" : "⌁"}</i>{title}{locked && <small>{t(language, "locked")}</small>}</button>; })}</nav><div className="user-card"><b>AL</b><div><strong>{t(language, "admin")}</strong><span>{t(language, "role")}</span></div></div></aside><div className="app-main"><header className="topbar"><strong>{t(language, "appName")}</strong><span className="online"><i /> {t(language, "online")}</span><input className="search" placeholder={t(language, "search")} /><div className="topbar-controls"><LanguageSwitch language={language} setLanguage={setLanguage} /><ThemeButton language={language} theme={theme} toggleTheme={toggleTheme} /></div></header><main className="page-content">{page === "dashboard" && <DashboardPage dataset={dataset} pipeline={pipeline} metrics={metrics} onStart={start} onCancel={cancel} go={setPage} />}{page === "eda" && <EdaPage dataset={dataset} onRefresh={refresh} go={setPage} />}{page === "training" && <TrainingPage pipeline={pipeline} metrics={metrics} figures={figures} metadata={metadata} onStart={start} onCancel={cancel} />}{page === "cv" && <CrossValidationPage rows={cv} onStart={start} />}{page === "tuning" && <TuningPage tuning={tuning} onStart={start} />}{page === "statistics" && <StatisticsPage statistics={statistics} />}{page === "reports" && <ReportsPage reports={reports} statistics={statistics} metrics={metrics} metadata={metadata} figures={figures} />}{page === "predict" && <PredictionPage metadata={metadata} />}</main><footer className="footer"><span>{t(language, "footer")}</span><span>{t(language, "footerRight")}</span></footer><ChatBot language={language} pipeline={pipeline} dataset={dataset} /></div></div>;
}

export default App;
